-- ════════════════════════════════════════════════════════════════════
--  TDLF-Educ · Built-in example content (10 subjects, 20 books, 100 quizzes)
--  Safe to re-run: it replaces only the seeded subjects' content.
--  Run AFTER schema.sql.  Paste into Supabase SQL Editor and Run.
-- ════════════════════════════════════════════════════════════════════

alter table public.quizzes add column if not exists options jsonb;

delete from public.quizzes where course_id in ('subj-math','subj-sci','subj-eng','subj-ict','subj-hist','subj-geo','subj-fil','subj-values','subj-pe','subj-arts');
delete from public.books   where course_id in ('subj-math','subj-sci','subj-eng','subj-ict','subj-hist','subj-geo','subj-fil','subj-values','subj-pe','subj-arts');

on conflict (id) do update set title = excluded.title;


